import React from "react";
import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022-Present",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2024",
    icon: <FaUniversity />,
    type: "cert",
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022",
    icon: <FaUniversity />,
    type: "cert",
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021-2022",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021",
    icon: <FaCloud />,
    type: "cert",
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014-2021",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019",
    icon: <FaUniversity />,
    type: "cert",
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013-2014",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008-2013",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001-2008",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001-2006",
    icon: <FaUniversity />,
    type: "edu",
  }
];

const ExperienceTimeline = () => {
  return (
    <div className="max-w-3xl mx-auto p-6">
      <div className="border-l-4 border-gray-400 pl-6">
        {experienceData.map((item, index) => (
          <div key={index} className="mb-10 relative">
            <div className="absolute -left-7 top-1 text-xl text-white bg-gray-800 rounded-full w-8 h-8 flex items-center justify-center">
              {item.icon}
            </div>
            <p className="text-sm text-gray-500">{item.date}</p>
            <h3 className="text-lg font-bold">
              {item.title}
            </h3>
            <p className="text-sm text-gray-700 italic">{item.company}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ExperienceTimeline;
